import{_ as t,o,c as n,i as a}from"./chunks/framework.2KsE0g5C.js";const g=JSON.parse('{"title":"Contributing to Cobalt","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/index.md","filePath":"contributing/index.md"}'),r={name:"contributing/index.md"};function i(s,e,l,d,c,u){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="contributing-to-cobalt" tabindex="-1">Contributing to Cobalt <a class="header-anchor" href="#contributing-to-cobalt" aria-label="Permalink to &quot;Contributing to Cobalt&quot;">​</a></h1><p>Thank you for your interest in contributing to the Cobalt Design System. Whether you&#39;re fixing a bug, proposing a new component, improving documentation, or sharing feedback, your contributions help make Cobalt better for everyone.</p><h2 id="ways-to-contribute" tabindex="-1">Ways to Contribute <a class="header-anchor" href="#ways-to-contribute" aria-label="Permalink to &quot;Ways to Contribute&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Contribution Type</th><th>Description</th><th>Getting Started</th></tr></thead><tbody><tr><td>Bug Reports</td><td>Found something broken? Let us know.</td><td><a href="./how-to-contribute.html">How to Contribute</a></td></tr><tr><td>Feature Requests</td><td>Have an idea for a new feature or enhancement?</td><td><a href="./how-to-contribute.html">How to Contribute</a></td></tr><tr><td>New Components</td><td>Propose and build a new component for the library.</td><td><a href="./component-proposal.html">Component Proposal</a></td></tr><tr><td>Code Contributions</td><td>Fix bugs, improve performance, or add features.</td><td><a href="./development-setup.html">Development Setup</a></td></tr><tr><td>Design Contributions</td><td>Propose design updates or new patterns in Figma.</td><td><a href="./design-contribution.html">Design Contribution</a></td></tr><tr><td>Documentation</td><td>Improve guides, examples, or API references.</td><td><a href="./development-setup.html">Development Setup</a></td></tr></tbody></table><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><ol><li><strong>Read the guidelines.</strong> Familiarize yourself with our <a href="./coding-standards.html">Coding Standards</a> and <a href="./versioning.html">Versioning &amp; Release Policy</a>.</li><li><strong>Check existing issues.</strong> Someone may already be working on what you have in mind. Search open issues and pull requests before starting new work.</li><li><strong>Start small.</strong> If this is your first contribution, look for issues labeled <code>good first issue</code> or <code>help wanted</code>.</li></ol><h2 id="contribution-workflow-at-a-glance" tabindex="-1">Contribution Workflow at a Glance <a class="header-anchor" href="#contribution-workflow-at-a-glance" aria-label="Permalink to &quot;Contribution Workflow at a Glance&quot;">​</a></h2><p>The general process for contributing code or design changes follows these stages:</p><ol><li><strong>Identify the work</strong> — Find an existing issue or create one describing the change</li><li><strong>Discuss</strong> — For non-trivial changes, get alignment by <a href="/cobalt-design-system/resources/contact.html">contacting us</a> starting</li><li><strong>Set up your environment</strong> — Follow the <a href="./development-setup.html">Development Setup</a> guide</li><li><strong>Implement</strong> — Make your changes on a feature branch, following the <a href="./coding-standards.html">Coding Standards</a></li><li><strong>Add a changeset</strong> — Run <code>pnpm changeset</code> so your change is included in the next release</li><li><strong>Submit a pull request</strong> — Open a PR against <code>main</code> and fill out the template</li><li><strong>Review and iterate</strong> — Address feedback from reviewers until the PR is approved</li><li><strong>Merge</strong> — A core maintainer merges the PR once all checks pass</li></ol><h2 id="governance-model" tabindex="-1">Governance Model <a class="header-anchor" href="#governance-model" aria-label="Permalink to &quot;Governance Model&quot;">​</a></h2><p>Cobalt is maintained by a dedicated design system team, but it is governed collaboratively:</p><ul><li><strong>Design Team</strong> - Owns the design language, visual guidelines, and Figma libraries, and tokenized design decisions.</li><li><strong>Dev Team</strong> — owns the codebase, reviews contributions, publishes releases, and maintains the web presence.</li><li><strong>Product Teams</strong> — submit requests, contribute components, and provide feedback on existing patterns.</li></ul><p>Product teams can contribute components directly. The process is:</p><ol><li>Propose the component via the <a href="./component-proposal.html">Component Proposal Process</a>.</li><li>The design system team provides a spec review and API guidance.</li><li>The product team builds the component following Cobalt conventions.</li><li>The design system team reviews, tests, and merges the contribution.</li></ol><blockquote><p><strong>Warning:</strong> Components that are merged into Cobalt become the responsibility of the design system team. Make sure the use case is general enough to justify long-term maintenance.</p></blockquote><h2 id="code-of-conduct" tabindex="-1">Code of Conduct <a class="header-anchor" href="#code-of-conduct" aria-label="Permalink to &quot;Code of Conduct&quot;">​</a></h2><p>All contributors are expected to follow our Code of Conduct. We are committed to providing a welcoming and inclusive experience for everyone. Please be respectful, constructive, and professional in all interactions.</p><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><p>If you&#39;re unsure where to start or have questions about the contribution process, visit our <a href="/cobalt-design-system/resources/contact.html">Contact</a> page for all support channels.</p><blockquote><p><strong>Tip:</strong> Don&#39;t be afraid to ask questions. The team is happy to help you find the right area to contribute and guide you through the process.</p></blockquote><h2 id="recognition" tabindex="-1">Recognition <a class="header-anchor" href="#recognition" aria-label="Permalink to &quot;Recognition&quot;">​</a></h2><p>We value every contribution. All contributors are acknowledged in our release notes, and significant contributions are highlighted in our quarterly design system newsletter.</p>',22)])])}const p=t(r,[["render",i]]);export{g as __pageData,p as default};
